// Aggregate context storage
const aggregateContexts = new Map();

// Helper functions
function makeNull() {
    return { valueType: 'null' };
}

function makeInteger(val) {
    return { valueType: 'integer', intValue: BigInt(val) };
}

function makeFloat(val) {
    return { valueType: 'float', floatValue: val };
}

function makeText(val) {
    return { valueType: 'text', textValue: String(val) };
}

function makeBlob(val) {
    return { valueType: 'blob', blobValue: val };
}

function getValue(sqlValue) {
    switch (sqlValue.valueType) {
        case 'integer': return Number(sqlValue.intValue);
        case 'float': return sqlValue.floatValue;
        case 'text': return sqlValue.textValue;
        case 'blob': return sqlValue.blobValue;
        case 'null':
        default: return null;
    }
}

/**
 * Scalar function dispatcher
 */
export function onScalarFunction(functionId, args) {
    switch (functionId) {
        case FUNC_SQLEAN_VERSION: {
            // sqlean_version() - return sqlean version string
            return makeText('0.1.0-wasm');
        }

        case FUNC_TEXT_SUBSTRING: {
            // text_substring(text, start [, length]) - extract substring
            if (args.length < 2) throw new Error('text_substring requires at least 2 arguments');
            const text = getValue(args[0]);
            const start = getValue(args[1]);
            if (text === null || start === null) return makeNull();
            const s = String(text);
            const idx = start - 1; // SQLite uses 1-based indexing
            if (args.length > 2) {
                const length = getValue(args[2]);
                return makeText(s.substring(idx, idx + length));
            }
            return makeText(s.substring(idx));
        }

        case FUNC_TEXT_SLICE: {
            // text_slice(text, start [, end]) - slice with Python-like semantics
            if (args.length < 2) throw new Error('text_slice requires at least 2 arguments');
            const text = getValue(args[0]);
            const start = getValue(args[1]);
            if (text === null || start === null) return makeNull();
            const s = String(text);
            const startIdx = start < 0 ? s.length + start : start;
            if (args.length > 2) {
                const end = getValue(args[2]);
                const endIdx = end < 0 ? s.length + end : end;
                return makeText(s.substring(startIdx, endIdx));
            }
            return makeText(s.substring(startIdx));
        }

        case FUNC_TEXT_LEFT:
        case FUNC_LEFT: {
            // left(text, n) - return first n characters
            if (args.length < 2) throw new Error('left requires 2 arguments');
            const text = getValue(args[0]);
            const n = getValue(args[1]);
            if (text === null || n === null) return makeNull();
            return makeText(String(text).substring(0, Math.max(0, n)));
        }

        case FUNC_TEXT_RIGHT:
        case FUNC_RIGHT: {
            // right(text, n) - return last n characters
            if (args.length < 2) throw new Error('right requires 2 arguments');
            const text = getValue(args[0]);
            const n = getValue(args[1]);
            if (text === null || n === null) return makeNull();
            const s = String(text);
            return makeText(s.substring(Math.max(0, s.length - n)));
        }

        case FUNC_TEXT_INDEX:
        case FUNC_STRPOS: {
            // strpos(text, substring) - return 1-based position of substring
            if (args.length < 2) throw new Error('strpos requires 2 arguments');
            const text = getValue(args[0]);
            const substr = getValue(args[1]);
            if (text === null || substr === null) return makeNull();
            const idx = String(text).indexOf(String(substr));
            return makeInteger(idx >= 0 ? idx + 1 : 0); // 1-based, 0 if not found
        }

        case FUNC_TEXT_LAST_INDEX: {
            // text_last_index(text, substring) - return 1-based position of last occurrence
            if (args.length < 2) throw new Error('text_last_index requires 2 arguments');
            const text = getValue(args[0]);
            const substr = getValue(args[1]);
            if (text === null || substr === null) return makeNull();
            const idx = String(text).lastIndexOf(String(substr));
            return makeInteger(idx >= 0 ? idx + 1 : 0);
        }

        case FUNC_TEXT_CONTAINS: {
            // text_contains(text, substring) - return 1 if contains, 0 otherwise
            if (args.length < 2) throw new Error('text_contains requires 2 arguments');
            const text = getValue(args[0]);
            const substr = getValue(args[1]);
            if (text === null || substr === null) return makeNull();
            return makeInteger(String(text).includes(String(substr)) ? 1 : 0);
        }

        case FUNC_TEXT_HAS_PREFIX:
        case FUNC_STARTS_WITH: {
            // starts_with(text, prefix) - return 1 if starts with prefix
            if (args.length < 2) throw new Error('starts_with requires 2 arguments');
            const text = getValue(args[0]);
            const prefix = getValue(args[1]);
            if (text === null || prefix === null) return makeNull();
            return makeInteger(String(text).startsWith(String(prefix)) ? 1 : 0);
        }

        case FUNC_TEXT_HAS_SUFFIX: {
            // text_has_suffix(text, suffix) - return 1 if ends with suffix
            if (args.length < 2) throw new Error('text_has_suffix requires 2 arguments');
            const text = getValue(args[0]);
            const suffix = getValue(args[1]);
            if (text === null || suffix === null) return makeNull();
            return makeInteger(String(text).endsWith(String(suffix)) ? 1 : 0);
        }

        case FUNC_TEXT_COUNT: {
            // text_count(text, substring) - count occurrences of substring
            if (args.length < 2) throw new Error('text_count requires 2 arguments');
            const text = getValue(args[0]);
            const substr = getValue(args[1]);
            if (text === null || substr === null) return makeNull();
            const s = String(text);
            const sub = String(substr);
            if (sub.length === 0) return makeInteger(0);
            let count = 0;
            let pos = 0;
            while ((pos = s.indexOf(sub, pos)) !== -1) {
                count++;
                pos += sub.length;
            }
            return makeInteger(count);
        }

        case FUNC_TEXT_LIKE: {
            // text_like(text, pattern) - SQL LIKE pattern matching (% and _)
            if (args.length < 2) throw new Error('text_like requires 2 arguments');
            const text = getValue(args[0]);
            const pattern = getValue(args[1]);
            if (text === null || pattern === null) return makeNull();
            // Convert SQL LIKE pattern to regex
            const regexStr = String(pattern)
                .replace(/[.*+?^${}()|[\]\\]/g, '\\$&') // Escape special regex chars
                .replace(/%/g, '.*')  // % matches any sequence
                .replace(/_/g, '.');   // _ matches single char
            const regex = new RegExp(`^${regexStr}$`, 'i');
            return makeInteger(regex.test(String(text)) ? 1 : 0);
        }

        case FUNC_TEXT_SPLIT:
        case FUNC_SPLIT_PART: {
            // split_part(text, delimiter, field) - extract field from split
            if (args.length < 3) throw new Error('split_part requires 3 arguments');
            const text = getValue(args[0]);
            const delim = getValue(args[1]);
            const field = getValue(args[2]);
            if (text === null) return makeNull();
            const parts = String(text).split(String(delim));
            const idx = field - 1; // 1-based
            return idx >= 0 && idx < parts.length ? makeText(parts[idx]) : makeText('');
        }

        case FUNC_TEXT_JOIN: {
            // text_join(separator, val1, val2, ...) - join values with separator
            if (args.length < 1) throw new Error('text_join requires separator and values');
            const sep = getValue(args[0]) || '';
            const parts = [];
            for (let i = 1; i < args.length; i++) {
                const v = getValue(args[i]);
                if (v !== null) parts.push(String(v));
            }
            return makeText(parts.join(sep));
        }

        case FUNC_CONCAT_WS: {
            // TODO: Implement concat_ws(-1 args)
            // Return type hint: any
            if (args.length < 1) throw new Error('concat_ws requires separator and values');
            const sep = getValue(args[0]) || '';
            const parts = [];
            for (let i = 1; i < args.length; i++) {
                const v = getValue(args[i]);
                if (v !== null) parts.push(String(v));
            }
            return makeText(parts.join(sep));
        }

        case FUNC_TEXT_CONCAT:
        case FUNC_CONCAT: {
            // concat(val1, val2, ...) - concatenate all values
            const parts = [];
            for (let i = 0; i < args.length; i++) {
                const v = getValue(args[i]);
                if (v !== null) parts.push(String(v));
            }
            return makeText(parts.join(''));
        }

        case FUNC_TEXT_REPEAT:
        case FUNC_REPEAT: {
            // repeat(text, count) - repeat text count times
            if (args.length < 2) throw new Error('repeat requires 2 arguments');
            const text = getValue(args[0]);
            const count = getValue(args[1]);
            if (text === null || count === null) return makeNull();
            return makeText(String(text).repeat(Math.max(0, count)));
        }

        case FUNC_TEXT_LTRIM:
        case FUNC_LTRIM: {
            // ltrim(text [, chars]) - remove leading characters
            if (args.length < 1) throw new Error('ltrim requires at least 1 argument');
            const text = getValue(args[0]);
            if (text === null) return makeNull();
            const s = String(text);
            if (args.length > 1) {
                const chars = String(getValue(args[1]) || ' ');
                let i = 0;
                while (i < s.length && chars.includes(s[i])) i++;
                return makeText(s.substring(i));
            }
            return makeText(s.trimStart());
        }

        case FUNC_TEXT_RTRIM:
        case FUNC_RTRIM: {
            // rtrim(text [, chars]) - remove trailing characters
            if (args.length < 1) throw new Error('rtrim requires at least 1 argument');
            const text = getValue(args[0]);
            if (text === null) return makeNull();
            const s = String(text);
            if (args.length > 1) {
                const chars = String(getValue(args[1]) || ' ');
                let i = s.length;
                while (i > 0 && chars.includes(s[i - 1])) i--;
                return makeText(s.substring(0, i));
            }
            return makeText(s.trimEnd());
        }

        case FUNC_TEXT_TRIM:
        case FUNC_BTRIM: {
            // trim(text [, chars]) - remove leading and trailing characters
            if (args.length < 1) throw new Error('trim requires at least 1 argument');
            const text = getValue(args[0]);
            if (text === null) return makeNull();
            const s = String(text);
            if (args.length > 1) {
                const chars = String(getValue(args[1]) || ' ');
                let start = 0;
                let end = s.length;
                while (start < end && chars.includes(s[start])) start++;
                while (end > start && chars.includes(s[end - 1])) end--;
                return makeText(s.substring(start, end));
            }
            return makeText(s.trim());
        }

        case FUNC_TEXT_LPAD: {
            // lpad(text, length [, fill]) - pad left
            if (args.length < 2) throw new Error('lpad requires at least 2 arguments');
            const text = getValue(args[0]);
            const length = getValue(args[1]);
            const fill = args.length > 2 ? String(getValue(args[2])) : ' ';
            if (text === null || length === null) return makeNull();
            return makeText(String(text).padStart(length, fill));
        }

        case FUNC_LPAD: {
            // lpad(text, length [, fill]) - pad left (duplicate, redirect to TEXT_LPAD)
            if (args.length < 2) throw new Error('lpad requires 2-3 arguments');
            const text = getValue(args[0]);
            const length = getValue(args[1]);
            const fill = args.length > 2 ? String(getValue(args[2])) : ' ';
            if (text === null || length === null) return makeNull();
            return makeText(String(text).padStart(length, fill));
        }

        case FUNC_TEXT_RPAD:
        case FUNC_RPAD: {
            // rpad(text, length [, fill]) - pad right
            if (args.length < 2) throw new Error('rpad requires 2-3 arguments');
            const text = getValue(args[0]);
            const length = getValue(args[1]);
            const fill = args.length > 2 ? String(getValue(args[2])) : ' ';
            if (text === null || length === null) return makeNull();
            return makeText(String(text).padEnd(length, fill));
        }

        case FUNC_TEXT_UPPER: {
            // text_upper(text) - convert to uppercase
            if (args.length < 1) throw new Error('text_upper requires 1 argument');
            const text = getValue(args[0]);
            if (text === null) return makeNull();
            return makeText(String(text).toUpperCase());
        }

        case FUNC_TEXT_LOWER: {
            // text_lower(text) - convert to lowercase
            if (args.length < 1) throw new Error('text_lower requires 1 argument');
            const text = getValue(args[0]);
            if (text === null) return makeNull();
            return makeText(String(text).toLowerCase());
        }

        case FUNC_TEXT_TITLE: {
            // text_title(text) - convert to title case
            if (args.length < 1) throw new Error('text_title requires 1 argument');
            const text = getValue(args[0]);
            if (text === null) return makeNull();
            return makeText(String(text).split(' ').map(w =>
                w.charAt(0).toUpperCase() + w.slice(1).toLowerCase()
            ).join(' '));
        }

        case FUNC_TEXT_CASEFOLD: {
            // text_casefold(text) - aggressive lowercase for comparison
            if (args.length < 1) throw new Error('text_casefold requires 1 argument');
            const text = getValue(args[0]);
            if (text === null) return makeNull();
            return makeText(String(text).toLowerCase());
        }

        case FUNC_TEXT_REPLACE: {
            // text_replace(text, from, to) - replace all occurrences
            if (args.length < 3) throw new Error('text_replace requires 3 arguments');
            const text = getValue(args[0]);
            const from = getValue(args[1]);
            const to = getValue(args[2]);
            if (text === null) return makeNull();
            return makeText(String(text).split(String(from)).join(String(to || '')));
        }

        case FUNC_TEXT_TRANSLATE:
        case FUNC_TRANSLATE: {
            // translate(text, from, to) - character-by-character translation
            if (args.length < 3) throw new Error('translate requires 3 arguments');
            const text = getValue(args[0]);
            const from = getValue(args[1]);
            const to = getValue(args[2]);
            if (text === null) return makeNull();
            const fromStr = String(from);
            const toStr = String(to || '');
            let result = '';
            for (const c of String(text)) {
                const idx = fromStr.indexOf(c);
                if (idx >= 0 && idx < toStr.length) {
                    result += toStr[idx];
                } else if (idx < 0) {
                    result += c;
                }
            }
            return makeText(result);
        }

        case FUNC_TEXT_REVERSE:
        case FUNC_REVERSE: {
            // reverse(text) - reverse characters in string
            if (args.length < 1) throw new Error('reverse requires 1 argument');
            const text = getValue(args[0]);
            if (text === null) return makeNull();
            // Use Array.from for proper Unicode support
            return makeText(Array.from(String(text)).reverse().join(''));
        }

        case FUNC_TEXT_LENGTH:
        case FUNC_CHAR_LENGTH:
        case FUNC_CHARACTER_LENGTH: {
            // char_length(text) - return character count
            if (args.length < 1) throw new Error('char_length requires 1 argument');
            const text = getValue(args[0]);
            if (text === null) return makeNull();
            // Use Array.from for proper Unicode character count
            return makeInteger(Array.from(String(text)).length);
        }

        case FUNC_TEXT_SIZE:
        case FUNC_OCTET_LENGTH: {
            // octet_length(text) - return byte count (UTF-8)
            if (args.length < 1) throw new Error('octet_length requires 1 argument');
            const text = getValue(args[0]);
            if (text === null) return makeNull();
            return makeInteger(Buffer.byteLength(String(text), 'utf8'));
        }

        case FUNC_TEXT_BITSIZE:
        case FUNC_BIT_LENGTH: {
            // bit_length(text) - return bit count (UTF-8 bytes * 8)
            if (args.length < 1) throw new Error('bit_length requires 1 argument');
            const text = getValue(args[0]);
            if (text === null) return makeNull();
            return makeInteger(Buffer.byteLength(String(text), 'utf8') * 8);
        }

        default:
            throw new Error(`Unknown function id: ${functionId}`);
    }
}

